var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JUDGE_CHARADE_NPC_NULL","text":{"KOREA":"이상, 중요 참고인들의 증언을 바탕으로…….","JPN":"以上、重要参考人の証言をもとに……","ENG":"In the light of the testimony provided by material witnesses...","TWN":"以上，根據幾位重要證人的證詞……"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JUDGE_CHARADE_NPC_NULL","text":{"KOREA":"피고의 간첩 행위 및 관리국의 핵심 기밀을 유출한 혐의가 사실로 밝혀졌습니다.","JPN":"被告のスパイ行為および管理局の核心的機密を漏洩させた疑いが事実であることが明らかになりました。","ENG":"It is evident that the defendant took part in espionage and leaked key secrets of the Administration.","TWN":"認定被告涉嫌從事間諜活動及洩漏管理局重要機密的罪證屬實，"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JUDGE_CHARADE_NPC_NULL","text":{"KOREA":"허나 피고는 여전히 잘못을 뉘우치지 않고, 범행을 부인하는 모습을 보이고 있습니다.","JPN":"ですが、被告はいまだに反省せず、犯行を否認する姿勢を見せています。","ENG":"However, she denies any involvement in the alleged offense and shows no remorse.","TWN":"然而，被告犯後毫無悔意，並且否認犯行，"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JUDGE_CHARADE_NPC_NULL","text":{"KOREA":"이에 따라, 본 재판부는 피고에게 종신형을 선고하는 바입니다.","JPN":"よって、本法廷は被告に終身刑を言い渡します。","ENG":"Accordingly, the court sentences the defendant to life imprisonment.","TWN":"因此，當庭宣判處以被告無期徒刑。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"남자한테 눈이 멀어서 핵심 기밀을 팔아 넘기다니…. 믿기지가 않아.","JPN":"男にハマって核心的機密を売り飛ばすとは……信じられない。","ENG":"I can't believe it... She sold the Administration's secrets all for a man she barely knows.","TWN":"被男人迷得團團轉洩漏出重要機密…真不敢相信。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까요. 남편이랑 애만 딱하게 됐네요.","JPN":"本当です。旦那さんとお子さんがかわいそうですよね。","ENG":"I know. I feel sorry for her husband and daughter.","TWN":"就是說啊，把老公和孩子害得這麼悽慘。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"불쌍할 게 뭐 있어? 남편도 한통속일지 누가 알아.","JPN":"何もかわいそうだなんて思う必要ないだろう？　旦那も一緒にやったのかもしれないし。","ENG":"Why do you feel sorry for them? Who knows? Maybe the husband was in on it too.","TWN":"有什麼好慘的？說不定她老公和她是一夥的，誰知道？"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"빼앗긴 아티팩트는 이제 무슨 수로 되찾아 올 건데?","JPN":"奪われたアーティファクトはどうやって取り戻すんだ？","ENG":"So how are they going to get back the stolen Artifact?","TWN":"現在要怎麼把被搶走的人造神器找回來？"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"사라졌다는 <color=#ffd34c>콜드 케이스</color>라는 게…… 그렇게 중요한 물건인가요?","JPN":"消えた<color=#ffd34c>コールドケース</color>って……そんなに大事な物なんですか？","ENG":"The missing <color=#ffd34c>Cold Case</color>... Is it that important?","TWN":"那個不見的<color=#ffd34c>Cold Case</color>……是很重要的東西嗎？"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"……쉿. 멍청아. 기밀 사항이라고. 목소리 낮춰.","JPN":"……しっ。バカ。機密事項なんだ。声を抑えろ。","ENG":"...Shush, you idiot. Keep your voice down! It's top secret.","TWN":"……噓！你這笨蛋，這可是機密，小聲一點！"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"믿고 있었는데…….","JPN":"信じてたのに……","ENG":"I trusted you...","TWN":"我那麼相信你……"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"솔직하게 말하면, 엄마랑 아빠가 감옥에 가지 않게 도와줄 거라고 했으면서!","JPN":"正直に話したら、ママとパパが刑務所に行かないようにしてくれるって言ったのに！","ENG":"You said that if I told the truth, that you would help Mommy and Daddy not go to jail!","TWN":"是你說不會讓爸爸媽媽進去坐牢的！"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"이럴 줄 알았으면…… 아무것도 말하지 말 걸…….","JPN":"こうなるとわかってたら……何も言わなかった……","ENG":"If I knew this was going to happen... I would've kept my mouth shut...","TWN":"早知道會這樣……我一句話都不會說……"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"나 때문에, 나 때문에 엄마, 아빠가…….","JPN":"私のせいで、私のせいでママとパパが……","ENG":"It's all because of me... that Mommy and Daddy are...","TWN":"都是我害的，都是我，害爸爸媽媽……"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"무슨 착각을 하는 거니, 루이즈?","JPN":"何を勘違いしてるのかしら？　ルイーズ。","ENG":"What are you talking about, Louisé?","TWN":"你是不是哪裡有誤會，露易絲？"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"네가 본 걸 숨겨 봤자, 너희 부모님이 저지른 죄가 없던 걸로 되는 건 아니잖아.","JPN":"あなたが見たことを隠しても、あなたの両親の犯した罪がなかったことにはならないわ。","ENG":"Even if you hide the truth, it doesn't make the crimes your parents committed go away.","TWN":"就算你不說你看到什麼，也不表示你父母就是無罪的。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"나도 안타깝지만, 죄 지은 사람은 그에 합당한 벌을 받아야지.","JPN":"私も残念だと思うけど、罪を犯した人はそれ相応の罰を受けないとね。","ENG":"It's a shame, but bad people must be punished for what they did.","TWN":"我也覺得很遺憾，但犯罪的人就該受到應有的懲罰。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"당신들은…….","JPN":"あなたたちは……","ENG":"You adults...","TWN":"你們這些大人……"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"당신들은 순 거짓말쟁이야……!","JPN":"あなたたちはみんな嘘つきだ……！","ENG":"You adults are all liars...!","TWN":"全都是騙子……！"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"subtitle","speaker":null,"text":{"KOREA":"코핀 컴퍼니 <color=#ffd34c>샤레이드 지부</color>","JPN":"コフィンカンパニーの<color=#ffd34c>シャレード支部</color>","ENG":"Coffin Company <color=#ffd34c>Charade Branch</color>","TWN":"科芬公司 <color=#ffd34c>查雷德分公司</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"카나리아 스쿼드, 본선 경기 시작 <color=#ffd34c>이틀 전</color>","JPN":"カナリア・スクワッド、本戦開始<color=#ffd34c>二日前</color>","ENG":"Canary Squad, <color=#ffd34c>2 days before</color> elimination rounds","TWN":"金絲雀小隊，決賽<color=#ffd34c>前二天</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이런 빈민가에 지부를 내다니…….","JPN":"こんなスラム街に支部を出すとは……","ENG":"Creating a branch in a slum like this...","TWN":"竟然把分公司設在貧民區……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"오는 길이 꽤나 험했어, 최고 관리자. 강도 미수만 세 번은 겪었으니까.","JPN":"ここに来るまでの道はかなり危険なものだったよ、最高管理者。強盗未遂だけでも3回はあったからな。","ENG":"It was quite the trip, Supreme Administrator. I almost got mugged three times on my way over here.","TWN":"來的路上很驚險欸，最高管理者。光是搶奪未遂就遇到三次吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 그건 마음씨 넓은 내가 이해해주도록 할까?","JPN":"まあ、それは心の広い私が理解してやってもいい。","ENG":"But having a heart of gold, I guess I should be understanding, right?","TWN":"不過誰叫我人美心善良，我就大人不記小人過吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 마음씨 넓으신 손님께서 여기 어쩐 일인가?","JPN":"それで、心の広いお客さんがここに何の用だ？","ENG":"So, what brings Ms. Heart-of-gold here?","TWN":"所以這位人美心善良的小姐，請問你來這裡有何貴幹？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"우린 지금 코핀 컴퍼니에서 압수한 자료들을 분석중이야.","JPN":"私たちは今コフィンカンパニーから押収した資料を分析しているところだ。","ENG":"We're analyzing the property we seized from Coffin Company.","TWN":"我們正在分析從科芬公司扣押的資料。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"솔직히 순조롭지는 않아. 애초에 파손된 장비들이 대부분이기도 하고.","JPN":"正直順調ではない。そもそもほとんどの装備が破損していてな。","ENG":"To be honest, it's not going so well. I mean, most of them were broken equipment after all.","TWN":"老實說不太順利，因為大部分是原本就壞掉的裝備。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"애석한 일이로군.","JPN":"それは残念だな。","ENG":"What a pity.","TWN":"我很遺憾。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흥, 시치미 떼지 마. 처음부터 우리에게 순순히 기술을 넘길 생각이 없던 거겠지.","JPN":"フン、しらばっくれるな。最初から素直に技術を渡すつもりなどなかったんだろう。","ENG":"Hmph, don't play dumb with me. You were never going to just hand over your technology to us, were you?","TWN":"哼，少在那邊裝蒜，你根本打從一開始就不打算乖乖地把技術交出來吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"우리도 바보는 아니야. 기술 격차라는 건 언젠가 반드시 따라잡히기 마련이지.","JPN":"私たちもバカではない。技術の差というものは、いつかは埋まるものだ。","ENG":"We're not that oblivious. It's only a matter of time before we catch up to your technology.","TWN":"不過我們也不是笨蛋，我們總有一天會追上這樣的技術落差的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만, 작전 현장에서 배포된 <color=#ffd34c>얼터니움 리액터</color>…….","JPN":"だが、作戦現場で配布された<color=#ffd34c>オルタニウムリアクター</color>……","ENG":"However, the <color=#ffd34c>Alternium Reactor</color> that was distributed at the operation...","TWN":"但是我問你，作戰現場的<color=#ffd34c>黑化永恆之金電抗器</color>……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"대체 그건 뭐지? 신기술이라고 얼버무릴 생각은 하지 마.","JPN":"あれはいったい何なんだ？　新技術といって誤魔化そうとするな。","ENG":"What is that? And don't try to gloss over it saying it's new technology.","TWN":"那到底是什麼？是新技術嗎？少跟我打哈哈喔！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아무런 대가도 없이, 그렇게 막대한 출력을 제공하는 물건이 세상에 존재할 리 없잖아.","JPN":"何の代償もなく、あれほど膨大な出力を出せるものがこの世に存在するわけないだろう？","ENG":"There's no way anything with that massive output at no cost can exist in this world.","TWN":"世界上怎麼可能有不需要付任何代價，就可以提供如此龐大輸出的東西！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니. 자네 말대로라네.","JPN":"いや。君の言うとおりさ。","ENG":"Yes, you are right.","TWN":"沒錯，正如你所說的。"},"stage":{"bg":"SS_SHADOW_07","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 세상에 대가가 없는 일이 어디 있겠나?","JPN":"この世に代償のいらないものなどない。","ENG":"Everything in this world must pay a price, no?","TWN":"天下沒有白吃的午餐。"},"stage":{"bg":"SS_SHADOW_07","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……뭐, 좋아. 어차피 단서가 없는 건 아니니까.","JPN":"……まあ、いい。手がかりがないわけでもないからな。","ENG":"...Well, all right. It's not like we don't have a lead or anything.","TWN":"……很好，反正我們也有掌握一些線索。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신 회사의 거래 내역을 추적해 봤더니, 폐기 판정 받은 이터니움을 꾸준히 매입해왔더군.","JPN":"あなたの会社の取引内容を追跡してみたが、廃棄されたエタニウムの買い取りを恒常的に行ってきたようだな。","ENG":"We traced back your company's transaction history and found that you kept buying Eternium marked for disposal.","TWN":"我們追蹤你們公司的交易紀錄，發現你們一直有在買進廢棄處理的永恆之金。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아마도 얼터니움이라는 건….","JPN":"おそらくオルタニウムというのは……","ENG":"So Alternium is...","TWN":"那個黑化永恆之金…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 폐기 판정을 받은 이터니움을 특수한 방법으로 가공한 무언가겠지. 안 그래?","JPN":"その廃棄されたエタニウムを、特殊な方法で加工した何かだろう。違うか？","ENG":"made by processing the Eternium marked for disposal in a special way, right?","TWN":"應該就是將廢棄處理的永恆之金以特殊方法加工後的產物，我說的沒錯吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"혼자서 거기까지 알아내다니 대단하군.","JPN":"一人でそこまで突き止めるとは、流石だな。","ENG":"I'm impressed you figured that out all on your own.","TWN":"竟然可以靠自己找到這些資料，蠻厲害的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 알려줄 수는 없네. 다른 사람에게 권할 만큼 안전한 방법이 아니야.","JPN":"だが、教えてやるわけにはいかない。他人にお勧めできるほど安全な方法ではないのでね。","ENG":"But I cannot go into detail. Just know that it is not safe enough to be recommended to others.","TWN":"不過恕我無可奉告，畢竟這不是適合推薦給別人的好方法。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흥, 나도 시니어이기 이전에 학자야.","JPN":"フン、私もシニアである前に学者だ。","ENG":"Hmph. You know, I may be a Senior, but I am a scholar too.","TWN":"哼，我在當Senior之前可是位學者好嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어디 그렇게 계속 감춰 보시지. 필요하다면 어떻게 해서든 알아낼 테니까.","JPN":"そうやってずっと隠してみろ。必要ならどんな手を使ってでも突き止めてやる。","ENG":"Let's see how well you keep this from me. But if needed, I will find out what it is one way or another.","TWN":"你就盡管藏著不說吧，必要的話我會想辦法找出答案的！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 응원하고 있겠네.","JPN":"はは、応援しよう。","ENG":"Ha ha, I'll be cheering you on.","TWN":"哈哈，加油。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서, 근황을 알려주려고 굳이 여기까지 먼 길을 온 건가?","JPN":"それで、近況を知らせるためだけに遠路はるばる訪ねてきたのか？","ENG":"So, you came all this way just to give me a progress report?","TWN":"所以你遠道而來，只是為了通知我你的近況嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……눈치는 빠르네.","JPN":"……気付いたか。","ENG":"...Well, you catch on quick.","TWN":"……蠻聰明的嘛。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 내가 여기 온 이유는 따로 있어.","JPN":"そうだ。私がここに来た理由は別にある。","ENG":"You're right. I'm here for a different reason.","TWN":"不錯，我來這裡是因為有其他的理由。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 전에…….","JPN":"だが、その前に……","ENG":"But before that...","TWN":"不過，在那之前……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐으으음…….","JPN":"ふむむむ……","ENG":"Hmmmm...","TWN":"嗯嗯嗯……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어때, 무슨 말 하는 지 들려?","JPN":"どうだ？　何話してるのか聞こえるか？","ENG":"So? Can you hear what they're talking about?","TWN":"怎麼樣？有偷聽他們在說什麼嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아뇨. 목소리가 너무 작게 들려서요.","JPN":"いいえ。声が小さすぎて。","ENG":"No. I can't hear them very well.","TWN":"沒有，聲音好小，根本聽不見。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런데 이렇게 사장님이랑 손님 대화를 엿들어도 괜찮을까요?","JPN":"でも、こうやって社長とお客様の会話を盗み聞きしてもいいんでしょうか？","ENG":"But are you sure it's okay to eavesdrop on Boss's conversation with his guest?","TWN":"不過這樣偷聽老闆跟客人對話沒關係嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저게 평범한 손님 같냐, 얼빵아?","JPN":"あれは普通の客じゃないんだよ、間抜け。","ENG":"You really think she's some ordinary guest, Goon?","TWN":"你看她像普通的客人嗎，小瓜呆？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저 여자, 코치를 만나러 여기까지 왔다면서.","JPN":"あの女、コーチに会うためにここまで来たんだろ？","ENG":"That woman came all this way to meet with Coach.","TWN":"那個女的是來找教練的，"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그럼 당연히 코치의 숨겨둔 애인 아니겠어? 이런 재밌는 상황을 놓칠 수는 없지.","JPN":"ってことは、当然コーチが秘密にしている彼女ってことだ。こんな面白い状況、見逃すわけにはいかないだろ。","ENG":"That has to make her his hidden lover, no? I can't miss something this entertaining!","TWN":"肯定是教練藏起來的女朋友吧？這麼精彩的事怎麼能夠錯過！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"애, 애인이라고요!?","JPN":"か、彼女！？","ENG":"L-lover?!","TWN":"女，女朋友！？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"신경 쓰지 마세요, 노엘. 라이카 머릿속에는 원래 저런 것밖에 없으니까.","JPN":"気にしないでください、ノエル。ライカの頭の中には、もともとああいったことしか入ってないんですから。","ENG":"Don't mind her, Noelle. Laika's head is always full of lewd things.","TWN":"別聽萊卡胡說，洛艾兒。她腦袋裡都裝那種東西。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"밖에 있는 경호원들 봤죠? 저 여자, 관리국의 고위 간부가 분명해요.","JPN":"外にいるボディーガードを見ましたよね？　あの女、きっと管理局の幹部クラスです。","ENG":"Didn't you see the bodyguards outside? I'm pretty sure that she's a high-ranking official of the Administration.","TWN":"有看到門外的保鑣嗎？那個女的一定管理局的高層。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어쩌면 코치는…….","JPN":"もしかしたら、コーチは……","ENG":"Maybe Coach is...","TWN":"說不定教練他……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제가 그 사람을 만나려는 이유는……","JPN":"私があの人に会おうとしてる理由は……","ENG":"The reason why I want to meet the person is...","TWN":"我之所以想見那個人……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"죽여 버리고 싶어서니까요.","JPN":"殺したいからです。","ENG":"Because I want to kill her.","TWN":"是因為我想殺了她。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아무튼 코치랑 저 여자가 어떤 관계인지 꼭 알아내야 해요.","JPN":"とにかく、コーチとあの女がどんな関係なのか、絶対確かめないと。","ENG":"Anyway, I must figure out what their relationship is.","TWN":"總之一定要弄清楚教練和她的關係。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어? 안쪽에서 갑자기 목소리가 끊겼어요.","JPN":"あれ？　中の話し声が急に途絶えました。","ENG":"Huh? The voices inside suddenly got cut off.","TWN":"嗯？裡面突然沒聲音了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우갹!?","JPN":"うぎゃっ！？","ENG":"Whoa?!","TWN":"哎喔！？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_WOOD"},{"id":"L47_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"직원 교육을 어떻게 하는 거야? 윗사람들 대화를 엿듣기나 하고.","JPN":"社員教育がなってないな。上司の話を盗み聞きするとは。","ENG":"How do you train your employees? Do they all have a habit of eavesdropping on their boss's conversations?","TWN":"你是怎麼教員工的？竟然偷聽高層談話。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우으으……! 죄송해요…….","JPN":"ううう……！　すみません……","ENG":"Ooh...! I'm sorry...","TWN":"嗚嗚嗚……！對不起……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그치만 손님이 사장님을 만나려고 그라운드 원에서 여기까지 찾아왔다고 하셨잖아요.","JPN":"でも、社長に会うためにグラウンド・ワンからここまで来たとおっしゃっていたじゃないですか。","ENG":"But you said you came all the way from Ground One to meet Boss.","TWN":"可是是你自己說你是從G1來找老闆的。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래서?","JPN":"それで？","ENG":"So?","TWN":"所以呢？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그래서 혹시 손님이 저희 사장님과 특별한 사이가 아닐까 했죠!","JPN":"それで、もしかしたらお客様が社長と特別な間柄ではないかと思いまして！","ENG":"So we thought you and Boss had some kind of special relationship!","TWN":"所以當然就會想說你是不是和老闆有什麼特殊關係嘛！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗! 손님!? 왜 갑자기 포옹을!?","JPN":"えっ！　お客様！？　なんでいきなりハグを！？","ENG":"Oh? Ma'am? Why are you suddenly hugging me?!","TWN":"啊！這位客人！？你幹嘛突然抱我！？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우와아아아아아아아앙!","JPN":"うわああああああああん！","ENG":"WAAAAAAHHH!","TWN":"哇啊啊啊啊啊啊！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저 여자! 느닷없이 수플렉스로 얼빵이를 내리꽂았어!","JPN":"あの女！　いきなりスープレックスで間抜けを投げ飛ばした！","ENG":"Whoa! She just dropped Goon with a suplex!","TWN":"她竟然！突然對小瓜呆使出摔角的背摔！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"누, 누가 특별한 사이야, 누가?","JPN":"だ、誰が特別な間柄だ、誰が？","ENG":"S-special relationship?! N-nonsense!","TWN":"誰，誰跟他有特殊關係啊？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"업무상 중요한 일 때문에 잠깐 들린 거라고!! 착각하지 마!!","JPN":"業務上、重要な用事があって少し寄っただけだ！！　勘違いするな！！","ENG":"I'm just here on important administrative matters!! Don't get any ideas!!","TWN":"我來找他是因為有重要的公事要談！！別胡說！！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘! 괜찮아요!?","JPN":"ノエル！　大丈夫ですか！？","ENG":"Noelle! Are you okay!?","TWN":"洛艾兒！你還好嗎！？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"히이… 하, 하늘에 별이 보여요. 하나, 둘…….","JPN":"ひいっ……お、お空にお星様が見えます。いち、に……","ENG":"I-I... see stars in the sky... One, two...","TWN":"嗚…我的頭頂有星星，一顆、二顆……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"경기를 앞둔 선수에게 폭력을 행사하면 어떡해요? 관리국이면 다예요?","JPN":"試合前の選手に暴力を振るうなんて。管理局だから許されるとでも思ってるんですか？","ENG":"How dare you exert violence on a player right before her match? You think being in the Administration gives you that power?","TWN":"怎麼可以對快要比賽的選手施暴！！管理局了不起嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"지금 당장 노엘한테 사과해요! 이 권력형 불륜녀야!","JPN":"今すぐノエルに謝ってください！　この権力型不倫女！","ENG":"Apologize to Noelle right now! You cheating, authoritative woman!","TWN":"你這個仗勢欺人的不良阿姨！立刻向洛艾兒道歉！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……は？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"꼬마야? 지금 내가 잘 못들은 것 같은데…… 다시 한 번 말해볼래?","JPN":"おチビ。今のは私の聞き間違いだと思うが……もう一度言ってくれないか？","ENG":"Hey, kiddo. Could you repeat what you just said? I must have misheard?","TWN":"小鬼？我沒聽錯吧……你可以再說一次嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"말해 보라면 못할 줄 알고? 이……","JPN":"できないと思ってるの？　この……","ENG":"What? You don't think I'll say it again? You–","TWN":"說就說，你以為我不敢啊？你這……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"읍읍!","JPN":"んぐっ！","ENG":"Mmff! Mff!","TWN":"唔唔！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 넌 진짜 눈에 뵈는 게 없냐?","JPN":"おい、お前マジでイカれたのか？","ENG":"Ugh, you really gotta learn to read the room.","TWN":"喂，你真的很白目欸！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"일어나, 노엘! 작전상 후퇴다!","JPN":"立て、ノエル！　とりあえず撤退だ！","ENG":"Get up, Noelle! We make a tactical retreat!","TWN":"洛艾兒快起來！撤退！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이 자식들! 거기 안 서!","JPN":"こいつら！　待て！","ENG":"You little brats! Stop right there!","TWN":"臭小鬼！給我站住！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하군. 직원들의 무례는 내가 대신 사과하지.","JPN":"すまない。社員の非礼は私が代わりに詫びよう。","ENG":"Sorry about that. I apologize on their behalf.","TWN":"抱歉，針對他們不禮貌的行為，我代替我的員工向你道歉。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"후우, 됐어.","JPN":"ふう、いい。","ENG":"*Sigh* Forget it.","TWN":"哼，算了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 저 애도 엄청 비뚤어졌네. 샤레이드는 역시 애들 키우기 좋은 곳이 못 돼.","JPN":"しかし、あの子も相当ひねくれてるな。シャレードはやはり子育てにはいい環境じゃない。","ENG":"But it seems she's become really sour. I guess it proves that Charade isn't a place to raise kids.","TWN":"不過那孩子怎麼變得越來越沒禮貌，查雷德果然不是個適合教養孩子的好地方。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"펠리세트에 대해 뭔가 알고 있나?","JPN":"フェリセットについて何か知っているのか？","ENG":"You know about Félicette?","TWN":"你認識費莉塞特嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"설마 다른 용건이라는 건, 펠리세트와 관련된 일인가?","JPN":"まさか他の用件というのは、フェリセットにまつわることなのか？","ENG":"The reason you came here, does it have something to do with Félicette?","TWN":"你說的事，跟費莉塞特有關嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐야, 당신? 저 아이에 대해서 뭔가 알고 도와주는 거 아니었어?","JPN":"何だ。あの子について知っていて手伝っているわけではなかったのか？","ENG":"What? Weren't you helping her out after learning about what she's been through?","TWN":"搞什麼？你什麼都不知道就聘請她嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"현지에서 우연히 알게 된 친구들일 뿐이라네.","JPN":"現地で偶然知り合った子たちなんだ。","ENG":"We coincidentally ran into them here.","TWN":"我是在這裡才認識她們的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그렇단 말이지…….","JPN":"なるほど……","ENG":"Is that so…","TWN":"原來……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신이 저 문제아를 데리고 건틀렛 리그에 출전했다는 건 이미 알고 있어.","JPN":"あなたがあの問題児を連れてガントレットリーグに出戦するということは知っていた。","ENG":"I already know you're participating in the Gauntlet with that delinquent child.","TWN":"我知道你要派那個問題兒童參加聖鎧聯賽。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"저 아이가 결승에 진출하려는 이유는…….","JPN":"あの子が決勝に進出しようとしている理由は……","ENG":"But the reason that kid wants to advance to the finals is...","TWN":"而她之所以參加比賽……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아마도 <color=#ffd34c>그 재판</color>때문이겠지.","JPN":"たぶん<color=#ffd34c>あの裁判</color>のせいだろう。","ENG":"probably because of <color=#ffd34c>the trial</color>.","TWN":"是因為<color=#ffd34c>那場官司</color>吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"재판이라?","JPN":"裁判？","ENG":"Trial?","TWN":"什麼官司？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흥, 하긴 시니어들 이름도 기억 안 하는데, 그런 사소한 사건들이야 알 리가 없나.","JPN":"フン、シニアたちの名前も覚えていないし、あんな些細な事件ならなおさらか。","ENG":"Hmph. You can't even remember the names of Seniors, so how would you know of a trivial case like that?","TWN":"哼，你連Senior的名字都不記得，這種小事不知道也是正常的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"저 아이의 부모는 관리국 연구원이었어. 수집한 아티팩트를 관리하는 역할이었지.","JPN":"あの子の親は管理局の研究員だった。収集したアーティファクトの管理を担当していたんだ。","ENG":"That child's parents were researchers at the Administration. They were tasked with managing Artifacts there.","TWN":"她的父母曾經是管理局的研究人員，負責管理收集來的人造神器。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그런데 그 중 하나가 사라진 거야.","JPN":"だが、その中の一つが消えた。","ENG":"But one of them went missing.","TWN":"但某一天其中一個人造神器不翼而飛。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"수사 과정에서는 <color=#ffd34c>북방합의체</color>가 연루되어 있다는 사실까지 밝혀졌고.","JPN":"捜査の過程で<color=#ffd34c>北方合意体</color>が関わっているという事実が明らかになってな。","ENG":"During the investigation, it was discovered that the <color=#ffd34c>Northern Union</color> was involved.","TWN":"調查過程中發現，他們勾結<color=#ffd34c>北方和議會</color>。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"담당자들이 아티팩트를 북방합의체에 팔아넘겼다고 본 건가?","JPN":"担当者がアーティファクトを北方合意体に売り渡したと見られたのか？","ENG":"Are you saying that they sold an Artifact to the Northern Union?","TWN":"他們將人造神器賣給北方和議會是嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래. 하지만 북방합의체와의 관계를 증명할 수는 없는 상황이었지.","JPN":"ああ。だが、北方合意体との関係を証明することはできない状況だった。","ENG":"Correct. But there was no actual way of proving their ties with the Northern Union.","TWN":"沒錯，但是沒有證據證明他們和北方和議會有勾結。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러다가 뜻밖의 증언으로 실마리가 풀린 거야.","JPN":"ところが、思いがけない証言から糸口がつかめた。","ENG":"Until one day, an unexpected testimony unraveled the whole case.","TWN":"後來是因為意料之外的證詞，使案情露出曙光。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"바로 저 아이야, 루이즈 로랑생.","JPN":"それがあの子だ、ルイーズ・ローランサン。","ENG":"That's her. Louisé Laurencin.","TWN":"就是她，露易絲·羅蘭桑的證詞。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"저 아이의 증언으로 아내 쪽의 외도 사실이 밝혀졌어.","JPN":"あの子の証言で、妻の方の浮気がバレた。","ENG":"Her testimony revealed that her mother was having an affair.","TWN":"根據她的證詞，發現她媽媽有外遇。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"상대 남성은 북방합의체의 스파이였지. 처음부터 아티팩트를 노리고 접근했던 거야.","JPN":"相手の男性は北方合意体のスパイでな。最初からアーティファクトを狙って接近したわけだ。","ENG":"The man was a Northern Union spy. He approached her with the intent of stealing the Artifact.","TWN":"而外遇對象就是北方和議會的間諜，男方從一開始就是為了人造神器才接近女方的。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 증언 이후에 유죄 판결이 확정되었고…….","JPN":"証言後に有罪判決が確定し……","ENG":"After Louisé's testimony, her mother was convicted...","TWN":"有了她的證詞，她的父母最後被判處有罪……"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"로랑생 부부는 모두 형이 집행되기 전에 스스로 목숨을 끊었지.","JPN":"ローランサン夫婦は二人とも、刑が執行される前に自殺したんだ。","ENG":"Both Mr. and Mrs. Laurencin, however, took their own lives before their sentence was executed.","TWN":"羅蘭桑夫婦則在入監前雙雙自殺死亡。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"아이의 증언만으로 내릴 판결은 아니군.","JPN":"子どもの証言だけで下すような判決ではないな。","ENG":"I don't think a child's testimony would have been enough for that sentence.","TWN":"怎麼可以光憑孩子的證詞就判有罪呢？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"스파이라는 건 어떻게 알아낸 거지?","JPN":"スパイだということはどうしてわかったんだ？","ENG":"How did they figure out that the man was a spy?","TWN":"怎麼知道對方是間諜的？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 재판에는 저 애 말고도 <color=#ffd34c>또 다른 증인</color>이 존재해.","JPN":"ああ。実は、裁判にはあの子の以外にも<color=#ffd34c>もう一人の証人</color>が存在する。","ENG":"You're right. There was <color=#ffd34c>another witness</color> besides her.","TWN":"沒錯，所以除了她之外，還有<color=#ffd34c>另一個證人</color>。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>오지만디아스</color>. 당시에는 리그에서 주가를 올리던 루키였지.","JPN":"<color=#ffd34c>オジマンディアス</color>。当時のリーグで評判のルーキーだった。","ENG":"<color=#ffd34c>Ozymandias</color>. At the time, she was an up-and-coming rookie in the league.","TWN":"就是<color=#ffd34c>奧茲曼迪亞斯</color>，她當時是在聯賽中身價水漲船高的新人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 사건은 관리국에 굉장히 불명예스러운 일이야.","JPN":"あの事件は管理局にとっては非常に不名誉なものだ。","ENG":"The Administration has been severely tarnished by this case.","TWN":"那件事對管理局而言不是一件光榮的事。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신의 도움으로 저 아이가 세상에 알려지면, 그 사건도 다시 조명 받겠지.","JPN":"あなたの助けであの子が世間に知られるようになれば、あの事件もまた注目されるだろう。","ENG":"If word gets out that you're helping her, her case will also resurface.","TWN":"要是因為你的幫助使她聲名大噪，那件事一定會再次受到關注。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"내부에서는 벌써 얘기가 오가고 있어. 당신의 행동은 전부 정치적으로 해석될 수 있으니까.","JPN":"内部ではすでに話し合いが始まっている。あなたの行動は、すべて政治的に解釈される可能性があるからな。","ENG":"There are already talks from inside. Your actions can all be interpreted as having a political agenda.","TWN":"這件事已經在內部傳開來，你的一舉一動都會被解讀成帶有政治意涵的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러니 저 아이를 돕는 건 이쯤에서 그만둬.","JPN":"だからあの子を助けるのはこのくらいにしておけ。","ENG":"So, I suggest you stop helping her.","TWN":"所以你還是收手吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"애초에 당신 목적은 건틀렛 리그가 아니라 시니어들과의 협상이잖아?","JPN":"そもそもあなたの目的はガントレットリーグではなく、シニアとの交渉だろう？","ENG":"I mean, your goal wasn't to enter the Gauntlet League but to negotiate with Seniors, right?","TWN":"你的目的不是聖鎧聯賽，而是和Senior談判不是嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"리하르트가 내건 조건 때문이라면, 차라리 저 애들 말고 다른 선수를 영입해.","JPN":"リヒャルトが出した条件のためなら、あの子たちではなくて他の選手をスカウトするんだな。","ENG":"If it's because of Richard's terms, I strongly advise you to recruit someone else.","TWN":"理查提出的條件是改派其他選手參賽。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"자네가 그렇게까지 날 걱정해줄 줄은 몰랐는데?","JPN":"君がそこまで私のことを心配してくれるとは、意外だな。","ENG":"I didn't think you'd be so worried about me.","TWN":"沒想到你這麼擔心我？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"미안하지만, 한 번 고용한 직원들을 버리진 않아.","JPN":"すまないが、一度雇った社員を切り捨てたりはしない主義なんだ。","ENG":"I'm sorry, but I don't abandon the people I hire.","TWN":"很抱歉，我是不會拋棄我的員工的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"자꾸 헛소리하면 진짜 날려버린다!?","JPN":"ふざけてると、本当にぶっ飛ばすぞ！？","ENG":"I'll beat you up if you keep talking nonsense!","TWN":"你再胡說八道我真的會飛踢你喔！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나는 진심일세.","JPN":"私は本気さ。","ENG":"I'm being serious.","TWN":"我是認真的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"부모가 죄를 저질렀다고 해도, 그게 아이를 외면할 이유는 될 수 없어.","JPN":"親が罪を犯したとしても、それが子どもから目を背ける理由にはならないさ。","ENG":"Whatever sin her parents committed doesn't justify my neglecting her.","TWN":"就算她的父母親犯罪，但那不足以構成我棄她於不顧的理由。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하아……. 마음대로 해.","JPN":"はあ……勝手にしろ。","ENG":"*Sigh...* Fine, do whatever you want.","TWN":"哀……隨便你吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 조심하는 게 좋을 거야. 여기 리그는 경기 결과 보다 스폰서들 입김이 더 중요하거든.","JPN":"だが、気をつけた方がいい。ここのリーグは試合の勝ち負けより、スポンサーの影響力を重視する。","ENG":"But you'd better be careful. The league is more influenced by its sponsors than the outcome of the matches.","TWN":"但我勸你小心一點，在這裡，影響聯賽結果的關鍵是贊助商。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그것들에게 갑자기 나타나서 본선에 진출한 당신 회사는, 눈엣가시나 마찬가지야.","JPN":"いきなり現れて本戦に進出したあなたの会社は、彼らにとっては目障りな存在以外の何者でもない。","ENG":"So, for your company to suddenly advance into elimination rounds will be a nuisance to them.","TWN":"你公司突然冒出來參加決賽，他們一定會視你為眼中釘的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러니 더 이상 <color=#ffd34c>정정당당</color>하게 싸워주진 않을 거라고.","JPN":"この先は<color=#ffd34c>正々堂々</color>と戦ってはくれないはずだ。","ENG":"In other words, they won't be fighting you <color=#ffd34c>fair and square</color>.","TWN":"而且他們一定不會使用<color=#ffd34c>正當手段</color>。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"부정행위에 조치를 취할 생각은 없나 보군.","JPN":"不正行為に対して措置を取る気はないようだな。","ENG":"I assume you don't plan on taking action for the malfeasance.","TWN":"看來你無意採取措施打擊作弊行為呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"예. 지배층의 불문율을 존중하기 때문이기도 하지만…….","JPN":"はい。支配階級の不文律を尊重しているためでもありますが……","ENG":"I'm afraid not. Primarily because I respect the unwritten law of the ruling class...","TWN":"是的，部分原因是出於尊重高層的淺規則。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"무엇보다도 당신의 능력을 증명하기에 이번 리그가 좋은 기회라고 판단했습니다.","JPN":"何よりもあなたの能力を証明するのに、今度のリーグがいい機会であると判断しました。","ENG":"But moreover, I consider this League to be a good opportunity for you to prove your abilities.","TWN":"最重要的是，我認為這次聯賽是證明您能力的好機會。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 부조리한 승부가 내 전문 분야라네.","JPN":"そのような不条理な勝負が私の専門分野だ。","ENG":"Well, unjust games are my specialty.","TWN":"在比賽中來陰的我最會。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"정정당당하게 싸우는 상대가 세상에 어디 있나?","JPN":"正々堂々と戦う相手など、この世にいないだろう？","ENG":"Since when did anyone fight fair and square?","TWN":"現在還有誰會在比賽中使用正當手段嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그렇게까지 말한다면, 나도 더 이상 말리진 않겠어.","JPN":"そこまで言うなら、私ももう止めない。","ENG":"If you want to go the hard way, then I won't stop you.","TWN":"既然如此，我也不會再說什麼。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"마음대로 해. 응원은 해주지.","JPN":"勝手にしろ。応援だけはしてやる。","ENG":"Do what you want. I'll be rooting for you.","TWN":"你開心就好，加油。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"성패와 별개로, 당신이 이런데서 져 버리면 우리 체면도 좀 그렇잖아?","JPN":"勝敗を抜きにしても、あなたがこんなところで負けてしまうと私たちの面子も立たないからな？","ENG":"Regardless of the outcome, it won't look good for any of us if you lose, right?","TWN":"不過先不說勝負，你要是在這種地方輸掉，我們的面子也掛不住，你知道吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};